    def _action_btn(self, parent, text, tooltip, color, cmd, right=False):
        glow = tk.Frame(parent, bg=color, padx=1, pady=1)
        glow.pack(side="right" if right else "left", padx=6)
        btn = tk.Button(glow, text=text, command=cmd,
                        bg=color, fg=BG_DARK,
                        activebackground=TEXT_MAIN, activeforeground=BG_DARK,
                        relief="flat", font=("Segoe UI", 9, "bold"),
                        padx=16, pady=6, cursor="hand2", bd=0)
        btn.pack()
        self._add_tooltip(btn, tooltip)
        btn.bind("<Enter>", lambda e, b=btn, c=color: b.config(bg=TEXT_MAIN, fg=BG_DARK))
        btn.bind("<Leave>", lambda e, b=btn, c=color: b.config(bg=c, fg=BG_DARK))
        return btn

